DECLARE
  x VARCHAR2(10);
  CURSOR c IS SELECT department_id FROM departments WHERE ROWNUM <= 1;
  v_id departments.department_id%TYPE;
BEGIN
  OPEN c;
  FETCH c INTO v_id;
  IF c%FOUND THEN
    DBMS_OUTPUT.PUT_LINE('X');
