What happens if a lock cannot be obtained due to the WAIT 5 option timing out?

Code:
SET SERVEROUTPUT ON
DECLARE
  CURSOR c IS SELECT * FROM product_information
  WHERE product_id NOT IN (SELECT product_id FROM order_items)
  FOR UPDATE OF list_price, min_price WAIT 5;
BEGIN
  FOR r IN c LOOP
    UPDATE product_information
    SET list_price = 0.95 * list_price, min_price = 0.95 * min_price
    WHERE CURRENT OF c;
  END LOOP;
  ROLLBACK;
EXCEPTION WHEN NO_DATA_FOUND THEN NULL;
END;

