What does the following PL/SQL block do?

Code:
SET SERVEROUTPUT ON
DECLARE
  TYPE tab_ind IS VARRAY(10000) OF employees%ROWTYPE;
  t tab_ind;
BEGIN
  SELECT * BULK COLLECT INTO t FROM employees WHERE ROWNUM <= 50 ORDER BY salary DESC;
  DBMS_OUTPUT.PUT_LINE('Number of elements ' || t.COUNT);
  FOR i IN t.FIRST .. t.LAST LOOP
    DBMS_OUTPUT.PUT_LINE(t(i).first_name || ' ' || t(i).last_name || '->' || i);
  END LOOP;
END;

What does the PL/SQL block output if there are employees earning more than 5000?

Code:
DECLARE
  CURSOR c IS SELECT * FROM employees WHERE salary > 5000;
  r c%ROWTYPE;
BEGIN
  OPEN c;
  FETCH c INTO r;
  CLOSE c;
  IF NOT c%FOUND THEN
    DBMS_OUTPUT.PUT_LINE('No rows found');
  ELSE
    DBMS_OUTPUT.PUT_LINE('Rows found');
  END IF;
END;

